const $ = (s, root = document) => root.querySelector(s);
const store = {
  get(key, fallback) { try { return JSON.parse(localStorage.getItem(`nexus:${key}`)) ?? fallback; } catch { return fallback; } },
  set(key, value) { localStorage.setItem(`nexus:${key}`, JSON.stringify(value)); }
};
const api = {
  async request(path, options = {}) {
    const token = store.get('token', '');
    const response = await fetch(`/api${path}`, { ...options, headers: { 'Content-Type':'application/json', ...(token ? { Authorization:`Bearer ${token}` } : {}), ...(options.headers || {}) } });
    const body = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(body.error || 'Server request failed');
    return body;
  },
  get(path){ return this.request(path); },
  post(path, body){ return this.request(path, { method:'POST', body:JSON.stringify(body) }); },
  patch(path, body){ return this.request(path, { method:'PATCH', body:JSON.stringify(body) }); }
};

