function persist(){ store.set('tasks',state.tasks); store.set('leave',state.leave); store.set('candidates',state.candidates); store.set('notifications',state.notifications); }
async function hydrate(){
  try { const data=await api.get('/bootstrap'); Object.assign(state,data); persist(); return true; }
  catch (error) { store.set('token',''); if(state.view==='app'){state.view='login';render();toast(error.message)} return false; }
}
function pill(status){ const c=/approved|completed|selected|available|healthy|present|resolved/i.test(status)?'green':/pending|review|medium|scheduled/i.test(status)?'orange':/high|overdue|critical|rejected/i.test(status)?'red':'blue'; return `<span class="pill ${c}">${status}</span>`; }
function stat(icon,value,label,tone='#e8f6d5',delta=''){return `<div class="stat" style="--tone:${tone}"><div class="stat-icon">${icon}</div><strong>${value}</strong><small>${label}</small>${delta?`<span class="delta">${delta}</span>`:''}</div>`}
function header(title,sub,action=''){return `<div class="page-head"><div><div class="eyebrow">${roleConfig[state.role].label} workspace</div><h1>${title}</h1><p>${sub}</p></div>${action}</div>`}

function layout(){
  const cfg=roleConfig[state.role];
  if(!cfg.modules.some(m=>m[0]===state.module)) state.module='dashboard';
  return `<div class="shell">
    <aside class="sidebar ${state.sidebar?'open':''}"><div class="brand"><div class="brand-mark">N</div><div><strong>Intern Nexus</strong><small>One workspace</small></div></div>
      <nav class="nav"><div class="nav-label">${cfg.label} menu</div>${cfg.modules.map(([id,name,icon])=>`<button data-nav="${id}" class="${state.module===id?'active':''}"><span class="nav-icon">${icon}</span><span>${name}</span></button>`).join('')}</nav>
      <div class="sidebar-foot"><div class="user-mini"><div class="avatar">${cfg.initials}</div><div><strong style="font-size:13px">${cfg.user}</strong><small style="display:block;color:#9db4a8;font-size:11px">${cfg.subtitle}</small></div></div><button class="btn ghost logout-btn" data-logout>Log out</button></div>
    </aside><main class="main"><header class="topbar"><button class="icon-btn menu-toggle" data-menu>☰</button><div class="search"><input id="globalSearch" placeholder="Search people, tasks, documents…"><span>⌕</span></div><div class="top-actions"><select class="role-select" id="roleSelect">${Object.entries(roleConfig).map(([k,v])=>`<option value="${k}" ${state.role===k?'selected':''}>${v.label}</option>`).join('')}</select><button class="icon-btn" data-notifications>♢<span class="badge">${state.notifications.length}</span></button></div></header>
      <section class="content">${state.module==='dashboard'?dashboard():modulePage(state.module)}</section></main>
    ${state.sidebar?'<div class="overlay" data-menu></div>':''}${state.notificationsOpen?notificationsPanel():''}</div>`;
}

function dashboard(){ return state.role==='intern'?internDashboard():state.role==='hr'?hrDashboard():state.role==='mentor'?mentorDashboard():adminDashboard(); }
function chart(){const a=[72,86,92,68,88,96,82],b=[35,50,40,62,30,48,55];return `<div class="chart">${a.map((v,i)=>`<div class="bar-group"><div class="bar" style="height:${v}%"></div><div class="bar alt" style="height:${b[i]}%"></div><span class="bar-label">${['M','T','W','T','F','S','S'][i]}</span></div>`).join('')}</div><div class="legend"><span><i class="dot" style="background:var(--green)"></i>Attendance</span><span><i class="dot" style="background:var(--lime)"></i>Task progress</span></div>`}

