function moduleHero(id){const m=moduleMeta[id]||[id[0].toUpperCase()+id.slice(1),'Manage this workspace module and its connected workflows.','◆',['Overview','Records','Analytics','Automation','Settings']];return `${header(m[0],m[1],`<button class="btn primary" data-open="${id}">＋ New ${m[0].replace(' Management','')}</button>`)}<div class="module-hero"><div class="big-icon">${m[2]}</div><div class="grow"><h2>${m[0]}</h2><p class="muted">Connected to the shared calendar, notifications, reports, audit log, and AI assistant.</p></div><span class="pill green">Live sync</span></div><div class="tabs">${m[3].map((t,i)=>`<button class="${i===0?'active':''}">${t}</button>`).join('')}</div>`}
function tasksPage(){return `${moduleHero('tasks')}<div class="stats">${stat('✓',state.tasks.length,'Total tasks')}${stat('◷',state.tasks.filter(x=>x.status==='Pending').length,'Pending','#fff0e8')}${stat('→',state.tasks.filter(x=>x.status==='In Progress').length,'In progress','#e7f1fb')}${stat('★',state.tasks.filter(x=>x.status==='Completed').length,'Completed','#e8f6d5')}</div><div class="card"><div class="card-head"><h2>Task workspace</h2><button class="btn accent" data-open="task">＋ Assign task</button></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Task</th><th>Project</th><th>Priority</th><th>Due</th><th>Progress</th><th>Status</th><th></th></tr></thead><tbody>${state.tasks.map(t=>`<tr><td><strong>${t.title}</strong><br><span class="muted">${t.id}</span></td><td>${t.project}</td><td>${pill(t.priority)}</td><td>${t.due}</td><td style="min-width:120px"><div class="progress"><i style="width:${t.progress}%"></i></div><small>${t.progress}%</small></td><td>${pill(t.status)}</td><td><button class="btn ghost" data-task-start="${t.id}">${t.status==='Pending'?'Start':'Update'}</button></td></tr>`).join('')}</tbody></table></div></div>`}
function leavePage(){return `${moduleHero('leave')}<div class="stats">${stat('□','12','Total allowed')}${stat('✓','3','Taken','#e7f1fb')}${stat('◷','1','Pending','#fff0e8')}${stat('☂','9','Remaining','#e8f6d5')}</div><div class="card"><div class="card-head"><h2>Leave requests</h2><button class="btn accent" data-open="leave">＋ Apply for leave</button></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Request</th><th>Type</th><th>Dates</th><th>Days</th><th>Reason</th><th>Status</th></tr></thead><tbody>${state.leave.map(x=>`<tr><td>${x.id}</td><td>${x.type}</td><td>${x.from} → ${x.to}</td><td>${x.days}</td><td>${x.reason}</td><td>${pill(x.status)}</td></tr>`).join('')}</tbody></table></div></div>`}
function attendancePage(){return `${moduleHero('attendance')}<div class="stats">${stat('◷','09:03','Check in','#e8f6d5')}${stat('⇥','—','Check out','#fff0e8')}${stat('⌛','5h 12m','Hours today','#e7f1fb')}${stat('↗','94%','This month','#f0e9fb')}</div><div class="grid"><div><div class="card"><div class="card-head"><h2>Attendance trend</h2><select class="role-select"><option>This week</option><option>This month</option></select></div>${chart()}</div><div class="card"><div class="card-head"><h2>Recent attendance</h2><button class="btn ghost" data-open="correction">Request correction</button></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Date</th><th>Check in</th><th>Check out</th><th>Hours</th><th>Status</th></tr></thead><tbody>${[['20 Jul','09:03','—','5h 12m','Present'],['19 Jul','08:56','17:42','8h 46m','Present'],['18 Jul','09:18','17:51','8h 33m','Late'],['17 Jul','09:01','17:38','8h 37m','Present']].map(x=>`<tr>${x.slice(0,4).map(y=>`<td>${y}</td>`).join('')}<td>${pill(x[4])}</td></tr>`).join('')}</tbody></table></div></div></div><div><div class="card" style="text-align:center"><div class="stat-icon" style="margin:auto;width:70px;height:70px;font-size:28px">⌖</div><h2 style="margin-top:15px">Inside office geofence</h2><p class="muted">42 m from JNS Startup Hub · Perimeter 150 m</p><button class="btn primary" style="width:100%;justify-content:center" data-attendance>Check out</button></div><div class="card"><h2>Work-hour summary</h2>${[['Daily average','8h 21m'],['Weekly total','32h 14m'],['Monthly total','118h 40m'],['Late entries','2']].map(x=>`<div class="activity"><div class="grow"><span class="muted">${x[0]}</span></div><strong>${x[1]}</strong></div>`).join('')}</div></div></div>`}
function recruitmentPage(){return `${moduleHero('recruitment')}<div class="stats">${stat('▤','320','Applications')}${stat('◎','48','Shortlisted','#e7f1fb')}${stat('◉','12','Interviews today','#fff0e8')}${stat('✓','18','Selected','#e8f6d5')}</div><div class="grid"><div><div class="card"><div class="card-head"><h2>Candidate pipeline</h2><button class="btn accent" data-open="candidate">＋ Add candidate</button></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Candidate</th><th>Position</th><th>College</th><th>AI match</th><th>Status</th><th></th></tr></thead><tbody>${state.candidates.map((c,i)=>`<tr><td><strong>${c.name}</strong></td><td>${c.role}</td><td>${c.college}</td><td><strong>${c.score}%</strong></td><td>${pill(c.status)}</td><td><button class="btn ghost" data-candidate="${i}">Move forward</button></td></tr>`).join('')}</tbody></table></div></div></div><div><div class="card"><h2>Recruitment funnel</h2>${[['Applications',320,100],['Shortlisted',80,25],['Interviewed',50,16],['Selected',20,6],['Joined',18,5]].map(x=>`<div style="margin-top:18px"><div style="display:flex;justify-content:space-between"><span class="muted">${x[0]}</span><strong>${x[1]}</strong></div><div class="progress"><i style="width:${x[2]}%"></i></div></div>`).join('')}</div><div class="card" style="background:#173c2e;color:white"><h2>AI screening</h2><p>24 new resumes analyzed. 6 candidates have a skill match above 90%.</p><button class="btn accent" data-ai>Review top candidates</button></div></div></div>`}
function assetsPage(){return `${moduleHero('assets')}<div class="stats">${stat('▣','86','Total assets')}${stat('✓','64','Issued','#e7f1fb')}${stat('□','14','Available','#e8f6d5')}${stat('!','8','Maintenance','#fdebea')}</div><div class="card"><div class="card-head"><h2>Asset register</h2><button class="btn accent" data-open="asset">＋ Issue asset</button></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Asset ID</th><th>Asset</th><th>Brand / Model</th><th>Assigned to</th><th>Return due</th><th>Status</th></tr></thead><tbody>${[['AST-0018','Laptop','Dell Latitude 5440','Joshua Martin','30 Aug','Issued'],['AST-0024','Monitor','LG 24MP60','Priya Nair','30 Aug','Issued'],['AST-0041','Laptop','Lenovo ThinkPad E14','—','—','Available'],['AST-0062','Laptop','HP ProBook 440','Maintenance team','—','Maintenance']].map(x=>`<tr>${x.slice(0,5).map(y=>`<td>${y}</td>`).join('')}<td>${pill(x[5])}</td></tr>`).join('')}</tbody></table></div></div>`}
function genericPage(id){const m=moduleMeta[id]||[id,'Unified workflow and operational management.','◆',['Overview','Records','Analytics','Automation','Settings']];const rows=[['NX-2401',`${m[0]} review`,roleConfig[state.role].user,'Today','In Progress'],['NX-2398',`${m[0]} verification`,'Operations team','21 Jul','Pending'],['NX-2384',`${m[0]} monthly summary`,'System automation','18 Jul','Completed'],['NX-2371',`${m[0]} exception`,'Support team','17 Jul','Review']];return `${moduleHero(id)}<div class="stats">${stat(m[2],'24','Total records')}${stat('◷','6','Pending','#fff0e8')}${stat('✓','16','Completed','#e8f6d5')}${stat('!','2','Needs attention','#fdebea')}</div><div class="grid"><div><div class="card"><div class="card-head"><h2>Recent records</h2><button class="btn ghost">Filter</button></div><div class="table-wrap"><table class="data-table"><thead><tr><th>ID</th><th>Record</th><th>Owner</th><th>Updated</th><th>Status</th></tr></thead><tbody>${rows.map(x=>`<tr>${x.slice(0,4).map(y=>`<td>${y}</td>`).join('')}<td>${pill(x[4])}</td></tr>`).join('')}</tbody></table></div></div></div><div><div class="card" style="background:#173c2e;color:white"><h2>AI recommendation</h2><p>Two items need attention. I can prioritize them, notify owners, and prepare a status summary.</p><button class="btn accent" data-ai>Run smart action</button></div><div class="card"><h2>Connected automation</h2>${['Calendar events synchronized','Notifications enabled','Reports included','Audit trail active'].map(x=>`<div class="activity"><span class="pill green">✓</span><div class="grow"><strong>${x}</strong></div></div>`).join('')}</div></div></div>`}

function activity(n){return `<div class="activity"><i class="dot" style="background:${n.type==='red'?'#ef5d57':n.type==='orange'?'#ff8f5c':n.type==='blue'?'#5b91ca':'#2e9169'}"></i><div class="grow"><strong>${n.title}</strong><span class="muted">${n.text}</span></div><small class="muted">${n.time}</small></div>`}
function notificationsPanel(){return `<div class="overlay" data-notifications></div><div class="notification-panel"><div class="card-head"><div><h2>Notifications</h2><span class="muted">Prioritized across every module</span></div><button class="icon-btn" data-notifications>×</button></div>${state.notifications.map(activity).join('')}<button class="btn ghost" style="width:100%;justify-content:center;margin-top:10px">Mark all as read</button></div>`}

function modal(kind){const defs={
  task:['Assign a new task',[['title','Task title','text'],['project','Project','text'],['due','Due date','date'],['priority','Priority','select'],['description','Requirements and expected outcome','textarea']]],
  leave:['Apply for leave',[['type','Leave type','select'],['from','From date','date'],['to','To date','date'],['reason','Reason','textarea']]],
  correction:['Attendance correction',[['date','Attendance date','date'],['in','Correct check-in time','time'],['out','Correct check-out time','time'],['reason','Reason for correction','textarea']]],
  candidate:['Add candidate',[['name','Full name','text'],['role','Applied position','text'],['college','College / university','text'],['email','Email address','email']]],
  announcement:['Post announcement',[['title','Announcement title','text'],['audience','Audience','select'],['message','Message','textarea']]],
  worklog:['Submit daily work log',[['date','Date','date'],['task','Task worked on','select'],['start','Start time','time'],['end','End time','time'],['description','Work completed','textarea'],['challenge','Challenges and next-day plan','textarea']]]
  ,['password-recovery']:['Recover your account',[['email','Registered email address','email'],['details','Enter your email to receive secure recovery instructions.','textarea']]]
  ,['support-request']:['Login support request',[['email','Contact email','email'],['category','Support category','select'],['details','Describe the sign-in problem','textarea']]]
  }; const d=defs[kind]||[`Create ${kind.replaceAll('-',' ')}`,[['title','Title','text'],['category','Category','select'],['details','Details','textarea']]];
  document.body.insertAdjacentHTML('beforeend',`<div class="overlay modal-layer"></div><form class="modal" id="actionForm" data-kind="${kind}"><div class="modal-head"><h2>${d[0]}</h2><button type="button" class="icon-btn" data-close>×</button></div><div class="form-grid">${d[1].map(([n,l,t])=>field(n,l,t)).join('')}</div><div class="modal-actions"><button type="button" class="btn ghost" data-close>Cancel</button><button class="btn primary">Save & notify</button></div></form>`);
}
function field(n,l,t){const full=t==='textarea'?' span-2':'';if(t==='textarea')return `<div class="field${full}"><label>${l}</label><textarea name="${n}" required></textarea></div>`;if(t==='select'){const opts=n==='priority'?['High','Medium','Low']:n==='type'?['Casual Leave','Sick Leave','Emergency Leave','Half Day','Work from Home']:n==='task'?state.tasks.map(x=>x.title):['Interns','Mentors','HR & Admin','Everyone'];return `<div class="field"><label>${l}</label><select name="${n}">${opts.map(x=>`<option>${x}</option>`).join('')}</select></div>`}return `<div class="field"><label>${l}</label><input name="${n}" type="${t}" ${t==='date'?'value="2026-07-20"':''} required></div>`}
function toast(msg){document.body.insertAdjacentHTML('beforeend',`<div class="toast">✓ ${msg}</div>`);setTimeout(()=>$('.toast')?.remove(),2600)}

function website(){return `<div class="public"><nav class="public-nav"><div class="public-brand"><div class="brand-mark">N</div> Intern Nexus</div><div class="public-links"><a href="#features">Features</a><a href="#internships">Internships</a><a href="#about">About</a><a href="#contact">Contact</a></div><button class="btn ghost" data-login>CRM Login</button></nav><section class="hero"><div class="hero-copy"><span class="hero-kicker">One intelligent internship workspace</span><h1>Where talent grows into <em>real impact.</em></h1><p>Connect interns, mentors, HR, and operations in one secure platform—from recruitment and onboarding to projects, performance, and certification.</p><div class="hero-actions"><button class="btn primary" data-login>Access your workspace →</button><a class="btn ghost" href="#features">Explore platform</a></div></div><div class="hero-visual"><div class="preview"><div class="preview-top"><i></i><i></i><i></i></div><span class="muted">Organization overview</span><h2 style="font:800 23px Manrope;margin:7px 0 18px">Everything moving together.</h2><div class="preview-grid"><div class="preview-card"><small>Active interns</small><strong>120</strong></div><div class="preview-card"><small>Team health</small><strong>92%</strong></div></div><div class="preview-chart">${[42,68,55,82,64,91,78].map(x=>`<i style="height:${x}%"></i>`).join('')}</div></div></div></section><section class="section" id="features"><div class="section-head"><span class="eyebrow">Unified by design</span><h2>One platform. Every internship moment.</h2><p>Automate repetitive work while keeping every person, approval, document, deadline, and conversation connected.</p></div><div class="feature-grid">${[['◎','Talent lifecycle','Recruit, onboard, manage, evaluate, certify, and transition interns without disconnected tools.'],['✓','Work & performance','Connect tasks, projects, work logs, meetings, attendance, goals, and mentor feedback.'],['✣','Intelligent automation','Surface risks, generate reports, prioritize approvals, and turn conversations into actions.'],['▣','Operations control','Manage assets, workspaces, refreshments, events, documents, leave, and helpdesk requests.'],['◇','Enterprise security','Role-based access, audit trails, protected documents, session controls, and system monitoring.'],['↗','Live insights','Real-time dashboards for interns, mentors, HR, and administrators with one shared source of truth.']].map(x=>`<article class="feature"><div class="feature-icon">${x[0]}</div><h3>${x[1]}</h3><p>${x[2]}</p></article>`).join('')}</div></section><section class="section alt" id="internships"><div class="section-head"><span class="eyebrow">Built for growth</span><h2>From first application to proud alumni.</h2><p>Intern Nexus creates a complete digital journey with clear ownership, timely support, measurable progress, and meaningful outcomes.</p><button class="btn primary" data-login>Sign in to CRM</button></div></section><footer class="public-footer"><strong>Intern Nexus</strong><span>© 2026 JNS · Intelligent internship management</span></footer></div>`}

function login(){return `<main class="login-page enterprise-login"><button class="login-back" data-home aria-label="Return to public website">← Back to website</button><div class="login-shell"><section class="login-story"><div class="public-brand"><div class="brand-mark">N</div><div>InternSync CRM<small>JNS Private Limited</small></div></div><span class="login-kicker">Enterprise Internship Platform</span><h1>Smart monitoring, coordination and analytics.</h1><p>Manage internship operations, communication, attendance, performance, and analytics from one secure platform.</p><div class="login-illustration" aria-hidden="true"><div class="secure-orbit"><span>◈</span><i></i><i></i><i></i></div><div><strong>Zero-Trust Gateway</strong><small>Identity · Device · Role · Risk</small></div><b>Protected</b></div>${['Role-verified secure access','Real-time operational intelligence','Protected organizational data'].map(x=>`<div class="login-benefit"><i>✓</i>${x}</div>`).join('')}<div class="security-message">◇ Your connection to this portal is encrypted and monitored.</div></section><section class="login-card-wrap"><form class="login-card" id="loginForm" novalidate><div class="login-card-top"><span class="eyebrow">Secure CRM access</span><div class="risk-chip"><i></i> Protected</div></div><h2>Welcome back</h2><p>Sign in to access your assigned workspace.</p><div class="field"><label for="loginRole">Select your role</label><select id="loginRole" name="role" required aria-describedby="roleHelp"><option value="">Select Role</option>${Object.entries(roleConfig).map(([k,v])=>`<option value="${k}">${v.label}</option>`).join('')}</select><small class="field-error" id="roleError"></small></div><div class="field"><label for="loginIdentity">Email address or username</label><div class="input-with-icon"><span>◎</span><input id="loginIdentity" type="text" name="identity" autocomplete="username" placeholder="name@company.com" required></div><small class="field-error" id="identityError"></small></div><div class="field"><div class="label-row"><label for="loginPassword">Password</label><button type="button" class="text-link" data-forgot>Forgot password?</button></div><div class="input-with-icon"><span>⚿</span><input id="loginPassword" type="password" name="password" autocomplete="current-password" placeholder="Enter your password" required><button type="button" class="password-toggle" data-password aria-label="Show password">Show</button></div><small class="field-error" id="passwordError"></small></div><div class="login-options"><label class="remember"><input type="checkbox" name="remember"> <span>Remember me on this trusted device</span></label><span class="session-note">12-hour secure session</span></div><div class="login-error" id="loginError" role="alert" aria-live="polite"></div><button class="btn primary login-submit" disabled><span>Sign In Securely</span><b>→</b></button><div class="login-support"><span>Need help signing in?</span><button type="button" class="text-link" data-support>Contact Support</button><i>·</i><button type="button" class="text-link" data-guide>Login Guide</button></div><div class="demo-credentials"><strong>Demo credentials</strong><span>Select a role to fill its authorized account.</span></div></form><div class="login-legal"><span>By signing in, you agree to the organization’s privacy and security requirements.</span><nav><a href="#privacy">Privacy Policy</a><a href="#terms">Terms of Use</a><a href="#security">Security Notice</a></nav><small>© 2026 JNS Private Limited</small></div></section></div></main>`}

function render(){if(state.view==='website'){document.title='Intern Nexus · Intelligent Internship Management';$('#app').innerHTML=renderPublicSite(state);bindPublic();return}if(state.view==='login'){document.title='Sign in · Intern Nexus';$('#app').innerHTML=login();bindPublic();return}document.title=`${roleConfig[state.role].label} · Intern Nexus`;$('#app').innerHTML=layout();bind();}
function bindPublic(){
  document.querySelectorAll('[data-login]').forEach(b=>b.onclick=()=>{state.view='login';render()});
  document.querySelectorAll('[data-home]').forEach(b=>b.onclick=()=>{state.view='website';render()});
  const form=$('#loginForm'); if(!form){bindPublicSite(state,api,render,()=>{state.view='login';render()},toast);return;}
  const role=$('#loginRole'),identity=$('#loginIdentity'),password=$('#loginPassword'),submit=$('.login-submit');
  const demos={intern:['intern@jns.com','Intern@123'],mentor:['mentor@jns.com','Mentor@123'],hr:['hr@jns.com','HR@123'],admin:['admin@jns.com','Admin@123']};
  const validate=()=>{const valid=role.value&&identity.value.trim().length>=3&&password.value.length>0;submit.disabled=!valid;return valid};
  role.onchange=()=>{if(demos[role.value]){[identity.value,password.value]=demos[role.value]}$('#roleError').textContent='';validate()};
  [identity,password].forEach(input=>input.oninput=()=>{input.value=input===identity?input.value.replace(/^\s+/,''):input.value;$(`#${input===identity?'identity':'password'}Error`).textContent='';$('#loginError').textContent='';validate()});
  $('[data-password]').onclick=e=>{const show=password.type==='password';password.type=show?'text':'password';e.currentTarget.textContent=show?'Hide':'Show';e.currentTarget.setAttribute('aria-label',show?'Hide password':'Show password')};
  $('[data-forgot]').onclick=()=>modal('password-recovery'); $('[data-support]').onclick=()=>modal('support-request'); $('[data-guide]').onclick=()=>toast('Login guide opened — select the role assigned to your account.');
  form.addEventListener('submit',async e=>{e.preventDefault();$('#loginError').textContent='';if(!validate()){if(!role.value)$('#roleError').textContent='Please select your assigned role.';if(identity.value.trim().length<3)$('#identityError').textContent='Please enter a valid email address or username.';if(!password.value)$('#passwordError').textContent='Password is required.';return}submit.disabled=true;submit.classList.add('loading');submit.querySelector('span').textContent='Authenticating your account…';const data=Object.fromEntries(new FormData(form));data.identity=data.identity.trim();try{const result=await api.post('/auth/login',data);submit.classList.remove('loading');submit.classList.add('success');submit.querySelector('span').textContent='Login successful. Redirecting…';store.set('token',result.token);state.role=result.user.role;state.module='dashboard';state.view='app';store.set('role',state.role);await hydrate();setTimeout(render,450)}catch(error){submit.classList.remove('loading');submit.disabled=false;submit.querySelector('span').textContent='Sign In Securely';$('#loginError').textContent=error.message==='Invalid email, password, or role'?'The credentials are incorrect or the selected role does not match this account.':'We could not complete your login request. Please try again.';form.classList.add('shake');setTimeout(()=>form.classList.remove('shake'),400)}})
}
function bind(){
  $('[data-logout]').onclick=async()=>{try{await api.post('/auth/logout',{})}catch{}store.set('token','');state.view='website';state.sidebar=false;render()};
  document.querySelectorAll('[data-nav]').forEach(b=>b.onclick=()=>{const id=b.dataset.nav;if(moduleMeta[id]||roleConfig[state.role].modules.some(m=>m[0]===id)){state.module=id;state.sidebar=false;store.set('module',id);render();}else toast('Workspace map is synchronized')});
  $('#roleSelect').onchange=e=>{state.role=e.target.value;state.module='dashboard';store.set('role',state.role);store.set('module','dashboard');render()};
  document.querySelectorAll('[data-notifications]').forEach(b=>b.onclick=()=>{state.notificationsOpen=!state.notificationsOpen;render()});
  document.querySelectorAll('[data-menu]').forEach(b=>b.onclick=()=>{state.sidebar=!state.sidebar;render()});
  document.querySelectorAll('[data-open]').forEach(b=>b.onclick=()=>modal(b.dataset.open));
  document.querySelectorAll('[data-ai]').forEach(b=>b.onclick=async()=>{try{await api.post('/records',{kind:'AI automation',action:b.textContent.trim()});await hydrate();render();toast('AI workflow started — connected modules updated')}catch(e){toast(e.message)}});
  document.querySelectorAll('[data-approve]').forEach(b=>b.onclick=()=>{b.closest('.approval').remove();toast('Item moved to approval review')});
  document.querySelectorAll('[data-attendance]').forEach(b=>b.onclick=async()=>{try{const row=await api.post('/attendance/check-out',{});await hydrate();render();toast('Check-out recorded at '+row.checkOut)}catch(e){toast(e.message)}});
  document.querySelectorAll('[data-task],[data-task-start]').forEach(b=>b.onclick=async()=>{const t=state.tasks.find(x=>x.id===(b.dataset.task||b.dataset.taskStart));if(t)try{await api.patch(`/tasks/${t.id}`,{status:t.status==='Completed'?'Completed':'In Progress',progress:Math.max(t.progress,25)});await hydrate();render();toast(`${t.title} updated`)}catch(e){toast(e.message)}});
  document.querySelectorAll('[data-candidate]').forEach(b=>b.onclick=async()=>{const i=+b.dataset.candidate,c=state.candidates[i],stages=['Review','Shortlisted','Interview','Selected'],status=stages[Math.min(stages.indexOf(c.status)+1,3)];try{await api.patch(`/candidates/${c.id}`,{status});await hydrate();render();toast(`${c.name} moved to ${status}`)}catch(e){toast(e.message)}});
  $('#globalSearch').onkeydown=e=>{if(e.key==='Enter'&&e.target.value.trim())toast(`Searching all modules for “${e.target.value.trim()}”`)};
}

document.addEventListener('click',e=>{if(e.target.matches('[data-close],.modal-layer'))document.querySelectorAll('.modal,.modal-layer').forEach(x=>x.remove())});
document.addEventListener('submit',async e=>{if(e.target.id!=='actionForm')return;e.preventDefault();const form=e.target,data=Object.fromEntries(new FormData(form)),kind=form.dataset.kind,button=form.querySelector('button[type="submit"],.modal-actions .primary');button.disabled=true;button.textContent='Saving…';try{if(kind==='task')await api.post('/tasks',data);else if(kind==='leave')await api.post('/leave',data);else if(kind==='candidate')await api.post('/candidates',data);else await api.post('/records',{kind,...data});await hydrate();document.querySelectorAll('.modal,.modal-layer').forEach(x=>x.remove());render();toast('Saved to server successfully')}catch(error){button.disabled=false;button.textContent='Save & notify';toast(error.message)}});

render();
if(state.view==='app') hydrate().then(ok=>{if(ok)render()});
if(state.view==='website') api.get('/public/programs').then(programs=>{state.programs=programs;render()}).catch(()=>{});
